import json
import time
import secrets
import hashlib
from datetime import datetime, timedelta
from typing import Optional, Dict, Any

from flask import Flask, request, jsonify
from flask_cors import CORS
from web3 import Web3
from eth_account.messages import encode_defunct
from functools import wraps

app = Flask(__name__)
CORS(app)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Initialize Web3
w3 = Web3()

# In-memory stores (use Redis/DB in production)
nonce_store: Dict[str, Dict[str, Any]] = {}  # address -> {nonce, expires_at}
session_store: Dict[str, Dict[str, Any]] = {}  # token -> {address, expires_at, created_at}
user_store: Dict[str, Dict[str, Any]] = {}  # address -> {registered_at, last_login, login_count}

# Configuration
NONCE_EXPIRY_SECONDS = 300  # 5 minutes
SESSION_EXPIRY_SECONDS = 3600  # 1 hour
MESSAGE_TEMPLATE = "Sign this message to authenticate with Web3Auth.\n\nWallet: {address}\nNonce: {nonce}\nTimestamp: {timestamp}"


def generate_nonce() -> str:
    """Generate a cryptographically secure random nonce."""
    return secrets.token_hex(16)


def generate_session_token() -> str:
    """Generate a secure session token."""
    return secrets.token_urlsafe(48)


def cleanup_expired_nonces():
    """Remove expired nonces from the store."""
    now = time.time()
    expired = [addr for addr, data in nonce_store.items() if data['expires_at'] < now]
    for addr in expired:
        del nonce_store[addr]


def cleanup_expired_sessions():
    """Remove expired sessions from the store."""
    now = time.time()
    expired = [token for token, data in session_store.items() if data['expires_at'] < now]
    for token in expired:
        del session_store[token]


def validate_ethereum_address(address: str) -> Optional[str]:
    """Validate and return checksummed Ethereum address."""
    try:
        if not address:
            return None
        checksummed = Web3.to_checksum_address(address)
        if Web3.is_address(checksummed):
            return checksummed
        return None
    except (ValueError, Exception):
        return None


def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({
                'success': False,
                'error': 'Missing or invalid Authorization header'
            }), 401

        token = auth_header[7:]
        session = session_store.get(token)

        if not session:
            return jsonify({
                'success': False,
                'error': 'Invalid session token'
            }), 401

        if session['expires_at'] < time.time():
            del session_store[token]
            return jsonify({
                'success': False,
                'error': 'Session expired'
            }), 401

        request.user_address = session['address']
        request.session_token = token
        return f(*args, **kwargs)

    return decorated_function


def recover_signer(message: str, signature: str) -> Optional[str]:
    """Recover the signer address from a signed message."""
    try:
        message_encoded = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            message_encoded,
            signature=signature
        )
        return Web3.to_checksum_address(recovered_address)
    except Exception as e:
        app.logger.error(f"Signature recovery failed: {e}")
        return None


@app.route('/api/v1/auth/nonce', methods=['POST'])
def request_nonce():
    """
    Request a nonce for wallet authentication.
    The client must sign this nonce to prove wallet ownership.
    """
    cleanup_expired_nonces()

    data = request.get_json()
    if not data or 'address' not in data:
        return jsonify({
            'success': False,
            'error': 'Ethereum address is required'
        }), 400

    address = validate_ethereum_address(data['address'])
    if not address:
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400

    nonce = generate_nonce()
    timestamp = datetime.utcnow().isoformat()
    expires_at = time.time() + NONCE_EXPIRY_SECONDS

    message = MESSAGE_TEMPLATE.format(
        address=address,
        nonce=nonce,
        timestamp=timestamp
    )

    nonce_store[address] = {
        'nonce': nonce,
        'message': message,
        'timestamp': timestamp,
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'data': {
            'message': message,
            'nonce': nonce,
            'expires_in': NONCE_EXPIRY_SECONDS
        }
    }), 200


@app.route('/api/v1/auth/verify', methods=['POST'])
def verify_signature():
    """
    Verify a signed message and authenticate the user.
    Returns a session token on successful verification.
    """
    cleanup_expired_nonces()
    cleanup_expired_sessions()

    data = request.get_json()
    if not data:
        return jsonify({
            'success': False,
            'error': 'Request body is required'
        }), 400

    required_fields = ['address', 'signature']
    missing = [f for f in required_fields if f not in data]
    if missing:
        return jsonify({
            'success': False,
            'error': f'Missing required fields: {", ".join(missing)}'
        }), 400

    address = validate_ethereum_address(data['address'])
    if not address:
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400

    signature = data['signature']
    if not signature or not isinstance(signature, str):
        return jsonify({
            'success': False,
            'error': 'Invalid signature format'
        }), 400

    # Ensure signature starts with 0x
    if not signature.startswith('0x'):
        signature = '0x' + signature

    # Check if nonce exists for this address
    nonce_data = nonce_store.get(address)
    if not nonce_data:
        return jsonify({
            'success': False,
            'error': 'No pending authentication challenge found. Request a nonce first.'
        }), 400

    # Check if nonce has expired
    if nonce_data['expires_at'] < time.time():
        del nonce_store[address]
        return jsonify({
            'success': False,
            'error': 'Authentication challenge has expired. Request a new nonce.'
        }), 400

    # Recover the signer from the signature
    message = nonce_data['message']
    recovered_address = recover_signer(message, signature)

    if not recovered_address:
        return jsonify({
            'success': False,
            'error': 'Failed to recover address from signature'
        }), 400

    # Verify the recovered address matches the claimed address
    if recovered_address.lower() != address.lower():
        # Invalidate the nonce to prevent replay
        del nonce_store[address]
        return jsonify({
            'success': False,
            'error': 'Signature verification failed. Recovered address does not match.'
        }), 401

    # Authentication successful - invalidate the nonce
    del nonce_store[address]

    # Create or update user record
    now = datetime.utcnow().isoformat()
    if address not in user_store:
        user_store[address] = {
            'address': address,
            'registered_at': now,
            'last_login': now,
            'login_count': 1
        }
    else:
        user_store[address]['last_login'] = now
        user_store[address]['login_count'] += 1

    # Generate session token
    session_token = generate_session_token()
    session_store[session_token] = {
        'address': address,
        'created_at': time.time(),
        'expires_at': time.time() + SESSION_EXPIRY_SECONDS
    }

    return jsonify({
        'success': True,
        'data': {
            'address': address,
            'token': session_token,
            'expires_in': SESSION_EXPIRY_SECONDS,
            'user': user_store[address]
        }
    }), 200


@app.route('/api/v1/auth/verify-token', methods=['POST'])
def verify_token():
    """Verify if a session token is still valid."""
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({
            'success': False,
            'error': 'Token is required'
        }), 400

    token = data['token']
    session = session_store.get(token)

    if not session:
        return jsonify({
            'success': False,
            'error': 'Invalid token'
        }), 401

    if session['expires_at'] < time.time():
        del session_store[token]
        return jsonify({
            'success': False,
            'error': 'Token expired'
        }), 401

    remaining = int(session['expires_at'] - time.time())

    return jsonify({
        'success': True,
        'data': {
            'address': session['address'],
            'valid': True,
            'expires_in': remaining
        }
    }), 200


@app.route('/api/v1/auth/refresh', methods=['POST'])
@require_auth
def refresh_session():
    """Refresh an existing session token."""
    old_token = request.session_token
    address = request.user_address

    # Invalidate old session
    if old_token in session_store:
        del session_store[old_token]

    # Create new session
    new_token = generate_session_token()
    session_store[new_token] = {
        'address': address,
        'created_at': time.time(),
        'expires_at': time.time() + SESSION_EXPIRY_SECONDS
    }

    return jsonify({
        'success': True,
        'data': {
            'token': new_token,
            'address': address,
            'expires_in': SESSION_EXPIRY_SECONDS
        }
    }), 200


@app.route('/api/v1/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Invalidate the current session."""
    token = request.session_token
    if token in session_store:
        del session_store[token]

    return jsonify({
        'success': True,
        'message': 'Successfully logged out'
    }), 200


@app.route('/api/v1/auth/logout-all', methods=['POST'])
@require_auth
def logout_all():
    """Invalidate all sessions for the authenticated user."""
    address = request.user_address
    tokens_to_remove = [
        token for token, data in session_store.items()
        if data['address'].lower() == address.lower()
    ]
    for token in tokens_to_remove:
        del session_store[token]

    return jsonify({
        'success': True,
        'message': f'Invalidated {len(tokens_to_remove)} session(s)'
    }), 200


@app.route('/api/v1/user/profile', methods=['GET'])
@require_auth
def get_profile():
    """Get the authenticated user's profile."""
    address = request.user_address
    user = user_store.get(address)

    if not user:
        return jsonify({
            'success': False,
            'error': 'User not found'
        }), 404

    # Count active sessions
    active_sessions = sum(
        1 for data in session_store.values()
        if data['address'].lower() == address.lower() and data['expires_at'] > time.time()
    )

    return jsonify({
        'success': True,
        'data': {
            **user,
            'active_sessions': active_sessions
        }
    }), 200


